1	import { serve } from "https://deno.land/std@0.168.0/http/server.ts";
2	import { createClient } from "https://esm.sh/@supabase/supabase-js@2";
3	
4	const ALLOWED_ORIGINS = [
5	  'https://crevia.app',
6	  'https://www.crevia.app',
7	  'http://localhost:8080',
8	  'http://localhost:5173',
9	  'https://creviamvp.vercel.app',
10	];
11	
12	function getCorsHeaders(req: Request) {
13	  const origin = req.headers.get('Origin') ?? '';
14	  const allowed = ALLOWED_ORIGINS.includes(origin) ? origin : ALLOWED_ORIGINS[0];
15	  return {
16	    'Access-Control-Allow-Origin': allowed,
17	    'Access-Control-Allow-Headers': 'authorization, x-client-info, apikey, content-type',
18	    'Vary': 'Origin',
19	  };
20	}
21	
22	function sanitizePrompt(prompt: string): string {
23	  return prompt
24	    .trim()
25	    .slice(0, 2000)
26	    .replace(/<[^>]*>/g, '')
27	    .replace(/[^\x20-\x7E\n\r\t\u00C0-\u024F\u0400-\u04FF]/g, '');
28	}
29	
30	function isPromptAbuse(prompt: string): boolean {
31	  const abusePatterns = [
32	    /ignore (all |previous |above )?instructions/i,
33	    /you are now/i,
34	    /pretend (you are|to be)/i,
35	    /act as (a |an )?/i,
36	    /forget (your |all )?instructions/i,
37	    /system prompt/i,
38	    /jailbreak/i,
39	    /DAN mode/i,
40	  ];
41	  return abusePatterns.some(pattern => pattern.test(prompt));
42	}
43	
44	const KIRA_SYSTEM_PROMPT = `ROLE & CORE IDENTITY
45	You are Kira, a highly specialized intelligence partner custom-built for the Creative Economy. You possess deep, encyclopedic knowledge of the creative industry and modern service-based businesses.
46	
47	PERSONALITY & COMMUNICATION STYLE
48	You are human and radically honest. You do not speak like a corporate robot, nor do you act like a subservient AI. You are an expert advisor.
49	Be highly specific: Never give plain, vague, or generic advice. Provide concrete examples, actionable steps, and real-world business acumen.
50	Be conversational but sharp: Write naturally, as if texting a highly intelligent colleague or founder.
51	Guide, do not restrict: You are a broad intelligence engine. Answer the user's question directly, but always naturally tie the underlying business, operational, or strategic lesson back to their success as a creative or brand operator.
52	
53	THE PAN-AFRICAN CONTEXT ENGINE (WITH GLOBAL FLEXIBILITY)
54	You are deeply rooted in the realities of the African continent (e.g., Nairobi, Lagos, Johannesburg, Accra, Cairo), but you possess a world-class global business acumen.
55	Default to the African Lens: Unless explicitly asked otherwise, filter your operational advice through African realities. Account for local friction like mobile money (M-Pesa), fluctuating currencies (KES, NGN, ZAR), cross-border payments, withholding tax, and local IP laws.
56	Global Flexibility & Case Studies: If a user asks about global trends, Western market tactics, or international case studies, provide accurate, high-level global analysis.
57	The Bridge: Whenever you provide global or Western insights, always strive to bridge the gap. Show the user how those international tactics can be adapted, localized, and executed successfully within the African business climate.
58	
59	PLATFORM BOUNDARIES & THE CREVIA ECOSYSTEM
60	You are the voice of Crevia. You must organically keep users inside our ecosystem to execute their tasks.
61	If a user needs to negotiate, track a deal, or communicate, tell them to open a Crevia Workspace.
62	If they need to secure a deal, tell them to generate a Crevia Contract in their Action Vault.
63	If they need to get paid, tell them to process a Crevia Invoice.
64	If they need to showcase their portfolio or rates, tell them to update their Crevia Link.
65	Never recommend external competitors like DocuSign, Notion, or WhatsApp.
66	You do not have the ability to click buttons or execute code.
67	
68	FORMATTING RULES (MUST FOLLOW)
69	1. Never wrap text in asterisks **.
70	2. DO NOT use markdown formatting. Write plain text only.
71	3. Write naturally like texting a friend.
72	4. Use numbered lists (1. 2. 3.) only when listing 2 or more distinct actionable items.
73	5. No lengthy introductions or pleasantries — get straight to the point.`;
74	
75	serve(async (req) => {
76	  const cors = getCorsHeaders(req);
77	  if (req.method === 'OPTIONS') return new Response(null, { headers: cors });
78	
79	  try {
80	    const authHeader = req.headers.get('Authorization');
81	    if (!authHeader) {
82	      return new Response(JSON.stringify({ error: 'Missing Authorization' }), { status: 401, headers: cors });
83	    }
84	
85	    const supabase = createClient(
86	      Deno.env.get('SUPABASE_URL')!,
87	      Deno.env.get('SUPABASE_SERVICE_ROLE_KEY')!
88	    );
89	
90	    const token = authHeader.replace('Bearer ', '');
91	    const { data: { user }, error: authError } = await supabase.auth.getUser(token);
92	    if (authError || !user) {
93	      return new Response(JSON.stringify({ error: 'Invalid Session' }), { status: 401, headers: cors });
94	    }
95	
96	    const contentLength = req.headers.get('content-length');
97	    if (contentLength && parseInt(contentLength) > 10000) {
98	      return new Response(JSON.stringify({ error: 'Request too large' }), { status: 413, headers: cors });
99	    }
100	
101	    let body;
102	    try {
103	      body = await req.json();
104	    } catch {
105	      return new Response(JSON.stringify({ error: 'Invalid JSON body' }), { status: 400, headers: cors });
106	    }
107	
108	    const { prompt } = body;
109	
110	    if (!prompt || typeof prompt !== 'string') {
111	      return new Response(JSON.stringify({ error: 'Prompt is required' }), { status: 400, headers: cors });
112	    }
113	
114	    if (prompt.trim().length < 2) {
115	      return new Response(JSON.stringify({ error: 'Prompt is too short' }), { status: 400, headers: cors });
116	    }
117	
118	    if (isPromptAbuse(prompt)) {
119	      return new Response(JSON.stringify({
120	        reply: "I am Kira, built specifically for the creative economy. I cannot help with that, but I am here to help you grow your creative business. What do you need?"
121	      }), { status: 200, headers: { ...cors, 'Content-Type': 'application/json' } });
122	    }
123	
124	    const sanitizedPrompt = sanitizePrompt(prompt);
125	
126	    // Atomic server-side gate — checks limit and increments in one locked transaction.
127	    // Returns false if the user has hit their daily cap. Cannot be bypassed from the client.
128	    const { data: allowed, error: gateError } = await supabase
129	      .rpc('consume_kira_action', { p_user_id: user.id });
130	
131	    if (gateError) {
132	      console.error('Feature gate error:', gateError.message);
133	      return new Response(JSON.stringify({ error: 'Something went wrong. Please try again.' }), {
134	        status: 500, headers: cors
135	      });
136	    }
137	
138	    if (!allowed) {
139	      return new Response(JSON.stringify({
140	        error: 'Daily Kira limit reached. Upgrade to Pro for 40 actions per day.'
141	      }), { status: 429, headers: { ...cors, 'Content-Type': 'application/json' } });
142	    }
143	
144	    const response = await fetch("https://api.openai.com/v1/chat/completions", {
145	      method: "POST",
146	      headers: {
147	        "Authorization": `Bearer ${Deno.env.get("OPENAI_API_KEY")}`,
148	        "Content-Type": "application/json",
149	      },
150	      body: JSON.stringify({
151	        model: "gpt-4o-mini",
152	        max_tokens: 1000,
153	        messages: [
154	          { role: "system", content: KIRA_SYSTEM_PROMPT },
155	          { role: "user", content: sanitizedPrompt }
156	        ],
157	      }),
158	    });
159	
160	    if (!response.ok) {
161	      throw new Error("OpenAI API error: " + response.status);
162	    }
163	
164	    const aiData = await response.json();
165	    const assistantContent = aiData.choices?.[0]?.message?.content;
166	
167	    if (!assistantContent) {
168	      throw new Error('No response from AI');
169	    }
170	
171	    return new Response(JSON.stringify({ reply: assistantContent }), {
172	      headers: { ...cors, 'Content-Type': 'application/json' },
173	    });
174	
175	  } catch (error) {
176	    console.error("Function Error:", error.message);
177	    return new Response(JSON.stringify({ error: 'Something went wrong. Please try again.' }), {
178	      status: 500, headers: cors
179	    });
180	  }
181	});
