22	/* To invoke locally:
23	
24	  1. Run `supabase start` (see: https://supabase.com/docs/reference/cli/supabase-start)
25	  2. Make an HTTP request:
26	
27	  curl -i --location --request POST 'http://127.0.0.1:54321/functions/v1/paystack-webhook' \
28	    --header 'Authorization: Bearer eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZS1kZW1vIiwicm9sZSI6ImFub24iLCJleHAiOjE5ODM4MTI5OTZ9.CRXP1A7WOeoJeXxjNni43kdQwgnWNReilDMblYTn_I0' \
29	    --header 'Content-Type: application/json' \
30	    --data '{"name":"Functions"}'
31	
32	*/
33	import { serve } from "https://deno.land/std@0.168.0/http/server.ts";
34	import { createClient } from "https://esm.sh/@supabase/supabase-js@2";
35	import { crypto } from "https://deno.land/std@0.168.0/crypto/mod.ts";
36	
37	const corsHeaders = {
38	  'Access-Control-Allow-Origin': '*',
39	  'Access-Control-Allow-Headers': 'authorization, x-client-info, apikey, content-type',
40	};
41	
42	serve(async (req) => {
43	  if (req.method === 'OPTIONS') {
44	    return new Response('ok', { headers: corsHeaders });
45	  }
46	
47	  try {
48	    const body = await req.text();
49	    //makes sure the request is from paystack by verifying the signature using the secret key(makes sure its from paystack and not a hacker trying to fake payment)
50	    const signature = req.headers.get('x-paystack-signature');
51	    const secret = Deno.env.get('PAYSTACK_SECRET_KEY')!;
52	
53	    // ✅ Verify webhook is actually from Paystack
54	    const key = await crypto.subtle.importKey(
55	      'raw',
56	      new TextEncoder().encode(secret),
57	      { name: 'HMAC', hash: 'SHA-512' },
58	      false,
59	      ['sign']
60	    );
61	    const signatureBuffer = await crypto.subtle.sign(
62	      'HMAC',
63	      key,
64	      new TextEncoder().encode(body)
65	    );
66	    const expectedSignature = Array.from(new Uint8Array(signatureBuffer))
67	      .map(b => b.toString(16).padStart(2, '0'))
68	      .join('');
69	
70	    if (expectedSignature !== signature) {
71	      return new Response(JSON.stringify({ error: 'Invalid signature' }), {
72	        status: 401,
73	        headers: corsHeaders,
74	      });
75	    }
76	
77	    const event = JSON.parse(body);
78	    const supabase = createClient(
79	      Deno.env.get('SUPABASE_URL')!,
80	      Deno.env.get('SUPABASE_SERVICE_ROLE_KEY')!
81	    );
82	
83	    // ✅ Handle successful charge(when a user successfully pays for subscription)
84	    if (event.event === 'charge.success') {
85	      const { customer, metadata, plan } = event.data;
86	      const userEmail = customer.email;
87	      const subscriptionPlan = metadata?.plan || 'creative_pro';
88	
89	      // Get user by email
90	      const { data: profile } = await supabase
91	        .from('profiles')
92	        .select('id, user_type')
93	        .eq('email', userEmail)
94	        .single();
95	
96	      if (profile) {
97	        const expiresAt = new Date();
98	        expiresAt.setMonth(expiresAt.getMonth() + 1);
99	
100	        await supabase
101	          .from('profiles')
102	          .update({
103	            subscription_plan: subscriptionPlan,
104	            subscription_status: 'active',
105	            subscription_expires_at: expiresAt.toISOString(),
106	            paystack_customer_code: customer.customer_code,
107	            kira_actions_limit: 40,
108	          })
109	          .eq('id', profile.id);
110	      }
111	    }
112	
113	    // ✅ Recurring renewal — extend expiry by one month and keep active
114	    if (event.event === 'subscription.create') {
115	      const { customer } = event.data;
116	      const expiresAt = new Date();
117	      expiresAt.setMonth(expiresAt.getMonth() + 1);
118	      await supabase
119	        .from('profiles')
120	        .update({
121	          subscription_status: 'active',
122	          subscription_expires_at: expiresAt.toISOString(),
123	        })
124	        .eq('email', customer.email);
125	    }
126	
127	    // ✅ Payment failed — cut off premium access automatically
128	    if (event.event === 'invoice.payment_failed') {
129	      const { customer } = event.data;
130	      await supabase
131	        .from('profiles')
132	        .update({ subscription_status: 'expired' })
133	        .eq('email', customer.email);
134	    }
135	    //we always tell paystack that the webhook has been received if not paystack will keep retrying the webhook
136	    return new Response(JSON.stringify({ received: true }), {
137	      status: 200,
138	      headers: { ...corsHeaders, 'Content-Type': 'application/json' },
139	    });
140	
141	  } catch (error) {
142	    console.error('Webhook error:', error.message);
143	    return new Response(JSON.stringify({ error: error.message }), {
144	      status: 500,
145	      headers: corsHeaders,
146	    });
147	  }
148	});
